"""state_service.py — 파일 시스템 접근 레이어.

핵심 원칙:
  - malformed run-state.json / events.jsonl 이 있어도 전체·목록 응답이 죽지 않는다.
  - 개별 run 파싱은 try/except 로 보호하고, 깨진 run 은 error 로 격리한다.
  - events.jsonl 의 깨진 줄은 skip 하고 정상 줄만 반환한다.
  - 파일은 읽기만 한다. 절대 쓰지 않는다 (이 서버는 읽기전용).
"""
import json
from pathlib import Path
from typing import Optional


def _read_text(path: Path) -> Optional[str]:
    try:
        return path.read_text(errors="replace")
    except OSError:
        return None


def read_run_state(state_dir: Path) -> tuple[Optional[dict], Optional[str]]:
    """run-state.json 을 파싱한다.

    반환: (state_dict | None, error | None)
      - 정상: (dict, None)
      - 파일 없음: (None, None)  → flat 파일 degrade 대상
      - 깨짐: (None, "malformed: ...")  → error 표시
    """
    path = state_dir / "run-state.json"
    if not path.is_file():
        return None, None
    try:
        return json.loads(path.read_text()), None
    except json.JSONDecodeError as exc:
        return None, f"malformed: {exc}"
    except OSError as exc:
        return None, f"io: {exc}"


def read_events(state_dir: Path) -> list[dict]:
    """events.jsonl 을 줄 단위로 파싱. 깨진 줄은 skip 한다."""
    path = state_dir / "events.jsonl"
    text = _read_text(path)
    if text is None:
        return []
    events: list[dict] = []
    for line in text.splitlines():
        line = line.strip()
        if not line:
            continue
        try:
            obj = json.loads(line)
        except json.JSONDecodeError:
            continue  # 깨진 줄 skip — 서버는 죽지 않는다
        if isinstance(obj, dict):
            events.append(obj)
    return events


def list_run_dirs(repo_dir: Path) -> list[Path]:
    """repo state 디렉터리 하위의 run 디렉터리들을 mtime 내림차순으로 반환.

    디렉터리가 없거나 읽을 수 없으면 빈 리스트. 절대 예외를 밖으로 던지지 않는다.
    """
    if not repo_dir.is_dir():
        return []
    runs: list[Path] = []
    try:
        for entry in repo_dir.iterdir():
            try:
                if entry.is_dir() and not entry.name.startswith("."):
                    runs.append(entry)
            except OSError:
                continue
    except OSError:
        return []
    try:
        runs.sort(key=lambda p: p.stat().st_mtime, reverse=True)
    except OSError:
        pass
    return runs


def events_path(state_dir: Path) -> Path:
    return state_dir / "events.jsonl"

"""main.py — FastAPI 앱 (읽기전용 GET 엔드포인트).

기동:
    uvicorn dashboard.server.main:app --host 127.0.0.1 --port 7419
또는:
    python3 -m dashboard.server.main

보호 정책: 127.0.0.1 에만 bind. 0.0.0.0 금지 (config.HOST 고정).
"""
import asyncio
import os

from fastapi import FastAPI, HTTPException
from fastapi.responses import JSONResponse, StreamingResponse

from . import config
from .services import run_service, state_service

app = FastAPI(
    title="Kant Dashboard",
    version=config.VERSION,
    description="읽기전용 로컬 관측 서버 (run-state.json / events.jsonl 기반)",
)


@app.get("/api/health")
def health():
    """200 { status, state_root, version }."""
    return {
        "status": "ok",
        "state_root": str(config.state_root()),
        "version": config.VERSION,
    }


@app.get("/api/runs")
def list_runs():
    """run 목록 (mtime 내림차순). run-state.json 없으면 flat 파일로 degrade."""
    try:
        return run_service.list_runs()
    except Exception as exc:  # 목록은 절대 500 으로 죽지 않는다
        return JSONResponse(
            status_code=500,
            content={"error": "list_failed", "detail": str(exc)},
        )


@app.get("/api/runs/{run_id}")
def run_detail(run_id: str):
    """run-state.json 전체. 없으면 404, 깨졌으면 error 표시(200)."""
    data, err, exists = run_service.get_run(run_id)
    if not exists:
        raise HTTPException(status_code=404, detail="run not found")
    if data is None:
        # run-state.json 없음(degrade) 또는 깨짐(malformed)
        body: dict = {"run_id": run_id}
        if err and err.startswith("malformed"):
            body["error"] = "malformed"
            body["detail"] = err
        else:
            body["error"] = "no_state"
            if err:
                body["detail"] = err
        return body
    return data


@app.get("/api/runs/{run_id}/events")
def run_events(run_id: str):
    """events.jsonl 파싱 배열. 깨진 줄은 skip. run 없으면 404."""
    events = run_service.get_events(run_id)
    if events is None:
        raise HTTPException(status_code=404, detail="run not found")
    return events


@app.get("/api/runs/{run_id}/stream")
async def run_stream(run_id: str):
    """SSE (text/event-stream). events.jsonl 을 tail 하며 새 이벤트를 push."""
    run_dir = run_service.run_dir_for(run_id)
    if run_dir is None:
        raise HTTPException(status_code=404, detail="run not found")
    events_path = state_service.events_path(run_dir)

    async def event_gen():
        offset = 0
        # 초기 backfill: 이미 존재하는 모든 이벤트를 먼저 내보낸다.
        try:
            if events_path.exists():
                with events_path.open("r", encoding="utf-8", errors="replace") as fh:
                    for line in fh:
                        line = line.strip()
                        if line:
                            yield f"data: {line}\n\n"
                    offset = fh.tell()
        except OSError:
            offset = 0

        # tail 루프 — 파일이 커지면 새 줄을 push.
        max_idle = int(os.environ.get("KANT_SSE_IDLE_ROUNDS", "0") or "0")  # 0 = 무한
        idle = 0
        while True:
            pushed = False
            try:
                size = events_path.stat().st_size if events_path.exists() else 0
            except OSError:
                size = 0
            if size > offset:
                try:
                    with events_path.open("r", encoding="utf-8", errors="replace") as fh:
                        fh.seek(offset)
                        for line in fh:
                            line = line.strip()
                            if line:
                                yield f"data: {line}\n\n"
                        offset = fh.tell()
                        pushed = True
                except OSError:
                    pass
            if pushed:
                idle = 0
            else:
                idle += 1
                if max_idle and idle >= max_idle:
                    yield ": done\n\n"
                    return
            await asyncio.sleep(1)

    return StreamingResponse(event_gen(), media_type="text/event-stream")


def main():
    """`python3 -m dashboard.server.main` 진입점. 127.0.0.1 전용 bind."""
    import uvicorn

    # HOST 를 config 로 고정 — CLI 인자나 환경변수로 0.0.0.0 으로 덮을 수 없게 한다.
    uvicorn.run(app, host=config.HOST, port=config.PORT, log_level="info")


if __name__ == "__main__":
    main()

